mapper.select:
SELECT approval_request_id, approval_document_type, approval_document_id,
       approval_request_type, approval_requester_id, approval_approver_id,
       approval_comment, approval_reason, approval_review_snapshot, approval_requested_at,
       approval_reviewed_at, approval_status
FROM approval_requests
WHERE approval_document_type = #{documentType}
  AND approval_document_id = #{documentId}
  AND approval_status = #{status}
